def test_init_zero_coef(
    base_loss, fit_intercept, n_features, dtype, global_random_seed
):
    loss = LinearModelLoss(base_loss=base_loss(), fit_intercept=fit_intercept)
    rng = np.random.RandomState(global_random_seed)
