def _asarray_with_order(
    array, dtype=None, order=None, copy=None, *, xp=None, device=None
):
    xp, _ = get_namespace(array, xp=xp)
    if _is_numpy_namespace(xp):
        # Use NumPy API to support order
        if copy is True:
            array = numpy.array(array, order=order, dtype=dtype)
        else:
            array = numpy.asarray(array, order=order, dtype=dtype)

        # At this point array is a NumPy ndarray. We convert it to an array
        # container that is consistent with the input's namespace.
        return xp.asarray(array)
    else:
        return xp.asarray(array, dtype=dtype, copy=copy, device=device)

def _safe_split(estimator, X, y, indices, train_indices=None):
    if get_tags(estimator).input_tags.pairwise:
        if not hasattr(X, "shape"):
            raise ValueError(
                "Precomputed kernels or affinity matrices have "
                "to be passed as arrays or sparse matrices."
            )
        # X is a precomputed square kernel matrix
        if X.shape[0] != X.shape[1]:
            raise ValueError("X should be a square kernel matrix")
        if train_indices is None:
            X_subset = X[np.ix_(indices, indices)]
        else:
            X_subset = X[np.ix_(indices, train_indices)]
    else:
        X_subset = _safe_indexing(X, indices)

    if y is not None:
        y_subset = _safe_indexing(y, indices)
    else:
        y_subset = None

    return X_subset, y_subset

def test_predict_proba_lr_large_values():

    class MockClassifier(LinearClassifierMixin, BaseEstimator):
        def __init__(self):
            pass

        def fit(self, X, y):
            self.__sklearn_is_fitted__ = True

        def decision_function(self, X):
            n_samples = X.shape[0]
            return np.tile([-1000.0] * 4, [n_samples, 1])

    clf = MockClassifier()
    clf.fit(X=None, y=None)

    proba = clf._predict_proba_lr(np.ones(5))
    assert_allclose(np.sum(proba, axis=1), 1)

